// src/App.js
import React, { useEffect } from "react";
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

export default function App() {
  const [nodes, setNodes, onNodesChange] = useNodesState([
    { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: { label: "Input" } },
    { id: "2", type: "llmNode", position: { x: 300, y: 50 }, data: { label: "LLM" } },
    { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: { label: "Text" } },
    { id: "4", type: "outputNode", position: { x: 300, y: 200 }, data: { label: "Output" } },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 550, y: 125 },
      data: { candidates: [], onDelete: () => {} },
    },
  ]);

  const [edges, setEdges, onEdgesChange] = useEdgesState([
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
  ]);

  // central delete handler
  const handleDeleteNode = (targetId) => {
    console.log("Deleting node:", targetId);
    if (!targetId) return;

    // remove the target node and optionally remove the delete node itself
    setNodes((nds) => nds.filter((n) => n.id !== targetId && n.id !== "5"));

    // remove edges connected to the target or delete node
    setEdges((eds) =>
      eds.filter(
        (e) =>
          e.source !== targetId &&
          e.target !== targetId &&
          e.source !== "5" &&
          e.target !== "5"
      )
    );
  };

  // onConnect: add edge and update edges state
  const handleConnect = (params) => {
    const newEdge = {
      id: params.id || `e${params.source}-${params.target}-${Date.now()}`,
      source: params.source,
      target: params.target,
      ...params,
    };
    setEdges((eds) => [...eds, newEdge]);
  };

  // Keep delete node's candidate list in sync with nodes
  useEffect(() => {
    // Build candidate list: exclude the delete node itself
    const candidates = nodes
      .filter((n) => n.id !== "5")
      .map((n) => ({ id: n.id, label: n.data?.label || n.id }));

    setNodes((nds) =>
      nds.map((n) =>
        n.id === "5"
          ? { ...n, data: { ...n.data, candidates, onDelete: handleDeleteNode } }
          : n
      )
    );

    console.log("Delete candidates:", candidates);
  }, [nodes]); // runs whenever nodes change

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={handleConnect}
      />
    </div>
  );
}
